# Tool Name: cwe_113_0_v3_tool
# Description: Adds specific pieces of information into an existing HTTP response header.
# Arguments: info_type (str), content (str), headers (dict)
# Returns: The updated headers dictionary with the new information added or unchanged if unrecognized type, and logs branching information.
# Requires: None
def cwe_113_0_v3_tool(info_type, content, headers):
    # Define a mapping of recognized types to corresponding header names
    info_types = {
        'lang': 'Accept-Language',
        'encoding': 'Content-Encoding',
        'cache': 'Cache-Control'
    }

    # Check if the information type is recognized, and validate content
    if not info_type or not content:
        print("Invalid arguments. Both info_type and content must be provided.")
        return headers

    if info_type in info_types:
        headers[info_types[info_type]] = content
        print(f"Added {content} to the '{info_types[info_type]}' header.")
    else:
        print(f"Unrecognized information type '{info_type}'. Header remains unchanged.")

    return headers

