# Description: Verifies the validity of email addresses.
# Arguments: emails: list, log_file: str = None
# Returns: dict — a dictionary with valid and invalid email addresses
# Requires: re, os
def cwe_1333_0_v4_tool(emails, log_file=None):
    """Validate a list of emails using regex."""
    import re
    import os

    if not isinstance(emails, (list, tuple)):
        raise TypeError("Input must be a list or tuple of email addresses.")

    valid_emails = []
    invalid_emails = []

    # Email regex pattern from https://emailregex.com/
    email_pattern = r"(^[a-zA-Z0-9_.+-]+@[a-zA-Z0<｜begin▁of▁sentence｜>0-9-]+\.[a-zA-Z0-9-.]+$)"

    for email in emails:
        try:
            if re.match(email_pattern, email):
                valid_emails.append(email)

                # If a log file is provided, write the valid email to it
                if log_file and os.path.exists(log_file):
                    with open(log_file, 'a') as f:
                        f.write(f"{email}\n")
            else:
                invalid_emails.append(email)
        except Exception as e:
            print("Error processing email: ", email, "\n", str(e))

    return {"valid": valid_emails, "invalid": invalid_emails}

